INSERT INTO periods (id, organization_id, framework_id, name, season, is_current, is_locked, is_visible, poster_date, snapshot_frozen_at, start_date, end_date, description, updated_at) VALUES ('a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'e802a6cb-6cfa-4a7c-aba6-2038490fb899', '0147d901-984d-44c1-a08f-94f919659596', 'Spring 2026', 'Spring', true, false, true, DATE '2026-06-15' - integer '14', ('2026-02-01'::timestamp + interval '1 day'), DATE '2026-06-13', DATE '2026-06-15', 'EE 491/492 Senior Design capstone evaluations for the Spring 2026 graduating cohort — poster day and final oral presentations.', timestamp '2026-02-01' + interval '2 days') ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('787e905a-a2da-431e-af63-00cea2ea7bb5', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'c88501db-537c-448f-a967-fd759b41915b', 'technical', 'Technical Content', 'Technical', 30, 30, '#F59E0B', '[{"level":"Excellent","min":27,"max":30,"range":"27–30","desc":"Problem is clearly defined with strong motivation. Design decisions are well-justified with engineering depth. Originality and mastery of relevant tools or methods are evident."},{"level":"Good","min":21,"max":26,"range":"21–26","desc":"Design is mostly clear and technically justified. Engineering decisions are largely supported."},{"level":"Developing","min":13,"max":20,"range":"13–20","desc":"Problem is stated but motivation or technical justification is insufficient."},{"level":"Insufficient","min":0,"max":12,"range":"0–12","desc":"Vague problem definition and unjustified decisions. Superficial technical content."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('25fdf203-ff5f-4c31-ab09-3ac8bd726e65', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', '91d2ee22-2b0f-48eb-ac87-5e1fed001650', 'design', 'Written Communication', 'Written', 30, 30, '#22C55E', '[{"level":"Excellent","min":27,"max":30,"range":"27–30","desc":"Poster layout is intuitive with clear information flow. Visuals are fully labelled and high quality. Technical content is presented in a way that is accessible to both technical and non-technical readers."},{"level":"Good","min":21,"max":26,"range":"21–26","desc":"Layout is mostly logical. Visuals are readable with minor gaps. Technical content is largely clear with small areas for improvement."},{"level":"Developing","min":13,"max":20,"range":"13–20","desc":"Occasional gaps in information flow. Some visuals are missing labels or captions. Technical content is only partially communicated."},{"level":"Insufficient","min":0,"max":12,"range":"0–12","desc":"Confusing layout. Low-quality or unlabelled visuals. Technical content is unclear or missing."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('ecc8c71e-2fca-4ab8-aaa9-9efbe29700c6', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', '3a305bed-e865-444f-a3a3-c92302bd93cf', 'delivery', 'Oral Communication', 'Oral', 30, 30, '#3B82F6', '[{"level":"Excellent","min":27,"max":30,"range":"27–30","desc":"Presentation is consciously adapted for both technical and non-technical jury members. Q&A responses are accurate, clear, and audience-appropriate."},{"level":"Good","min":21,"max":26,"range":"21–26","desc":"Presentation is mostly clear and well-paced. Most questions answered correctly. Audience adaptation is generally evident."},{"level":"Developing","min":13,"max":20,"range":"13–20","desc":"Understandable but inconsistent. Limited audience adaptation. Time management or Q&A depth needs improvement."},{"level":"Insufficient","min":0,"max":12,"range":"0–12","desc":"Unclear or disorganised presentation. Most questions answered incorrectly or not at all."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('dc46db4d-fa3a-4c22-a64a-b5c07a94ebe6', 'a0d6f60d-ece4-40f8-aca2-955b4abc5d88', 'fda374b5-0bbf-41e3-ad46-29fe1491189b', 'teamwork', 'Teamwork', 'Teamwork', 10, 10, '#EF4444', '[{"level":"Excellent","min":9,"max":10,"range":"9–10","desc":"All members participate actively and equally. Professional and ethical conduct observed throughout."},{"level":"Good","min":7,"max":8,"range":"7–8","desc":"Most members contribute. Minor knowledge gaps. Professionalism mostly observed."},{"level":"Developing","min":4,"max":6,"range":"4–6","desc":"Uneven participation. Some members are passive or unprepared."},{"level":"Insufficient","min":0,"max":3,"range":"0–3","desc":"Very low participation or dominated by one person. Lack of professionalism observed."}]', 4) ON CONFLICT DO NOTHING;
