INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('a436fb51-aa71-4afc-a9bf-2232d151fbaa', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'c88501db-537c-448f-a967-fd759b41915b', 'technical', 'Technical Content & Innovation', 'Technical', 35, 35, '#F59E0B', '[{"level":"Excellent","min":31,"max":35,"range":"31–35","desc":"Exceptional technical depth: problem is framed as an engineering challenge, solution is innovative, and all design decisions cite appropriate standards or literature. Mastery of advanced tools/methods demonstrated."},{"level":"Good","min":24,"max":30,"range":"24–30","desc":"Strong technical quality. Design is clearly motivated and most decisions are justified. Some advanced methods applied correctly."},{"level":"Developing","min":14,"max":23,"range":"14–23","desc":"Problem statement is adequate but technical justification is inconsistent. Some decisions lack engineering rationale."},{"level":"Insufficient","min":0,"max":13,"range":"0–13","desc":"Technical content is superficial or incomplete. Problem is poorly defined and design decisions are not supported."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('8cebf54b-97b4-493c-a837-4707d4828eae', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', '91d2ee22-2b0f-48eb-ac87-5e1fed001650', 'design', 'Poster & Visual Communication', 'Poster', 30, 30, '#22C55E', '[{"level":"Excellent","min":27,"max":30,"range":"27–30","desc":"Poster is visually compelling and immediately communicates the project''s value proposition. Hierarchy of information is clear. Visuals are publication-quality and fully captioned."},{"level":"Good","min":21,"max":26,"range":"21–26","desc":"Poster communicates the project clearly. Information hierarchy is mostly followed with minor layout issues. Visuals are readable and mostly labelled."},{"level":"Developing","min":13,"max":20,"range":"13–20","desc":"Poster conveys basic information but visual hierarchy is unclear. Some visuals are low quality or uncaptioned. Reader effort required to follow the content."},{"level":"Insufficient","min":0,"max":12,"range":"0–12","desc":"Poster is difficult to read or visually disorganised. Key information is missing or misleading. Unlabelled or irrelevant visuals."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('bb41dca1-a7d3-4fa8-a819-cd1d0c92bdf2', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', '3a305bed-e865-444f-a3a3-c92302bd93cf', 'delivery', 'Oral Presentation', 'Oral', 25, 25, '#3B82F6', '[{"level":"Excellent","min":22,"max":25,"range":"22–25","desc":"Delivery is confident and well-timed. The team adapts explanations for the jury composition. All questions answered accurately with appropriate depth."},{"level":"Good","min":17,"max":21,"range":"17–21","desc":"Delivery is clear and mostly well-paced. Most questions answered correctly. Minor issues with time or audience adaptation."},{"level":"Developing","min":10,"max":16,"range":"10–16","desc":"Delivery is understandable but hesitant or poorly paced. Some questions partially answered. Limited engagement with the jury."},{"level":"Insufficient","min":0,"max":9,"range":"0–9","desc":"Delivery is unclear, rushed, or disorganised. Critical questions unanswered or incorrectly addressed."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('ae079c87-3d0a-4aa9-ae5b-8966b4f38a57', '952dd05e-8ff2-44a7-a13b-9a22958f57fb', 'fda374b5-0bbf-41e3-ad46-29fe1491189b', 'teamwork', 'Teamwork', 'Teamwork', 10, 10, '#EF4444', '[{"level":"Excellent","min":9,"max":10,"range":"9–10","desc":"All members participate actively and equally. Professional and ethical conduct observed throughout."},{"level":"Good","min":7,"max":8,"range":"7–8","desc":"Most members contribute. Minor knowledge gaps. Professionalism mostly observed."},{"level":"Developing","min":4,"max":6,"range":"4–6","desc":"Uneven participation. Some members are passive or unprepared."},{"level":"Insufficient","min":0,"max":3,"range":"0–3","desc":"Very low participation or dominated by one person. Lack of professionalism observed."}]', 4) ON CONFLICT DO NOTHING;
