INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('5c1f4f21-151a-4b22-a335-5ef961d9e99f', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', 'c88501db-537c-448f-a967-fd759b41915b', 'technical', 'Technical Content', 'Technical', 30, 30, '#F59E0B', '[{"level":"Excellent","min":27,"max":30,"range":"27–30","desc":"Rigorous methodology is applied throughout. All technical decisions are traceable to engineering requirements or experimental results."},{"level":"Good","min":21,"max":26,"range":"21–26","desc":"Methodology is mostly sound. Key decisions are supported; minor gaps in documentation or justification."},{"level":"Developing","min":13,"max":20,"range":"13–20","desc":"Methodology described but lacking depth. Some decisions are made without full engineering analysis."},{"level":"Insufficient","min":0,"max":12,"range":"0–12","desc":"No discernible methodology. Technical decisions appear arbitrary or are largely absent."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('15dca296-abd2-4fd9-adb3-ff2d66b91858', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', '91d2ee22-2b0f-48eb-ac87-5e1fed001650', 'design', 'Written Communication', 'Written', 30, 30, '#22C55E', '[{"level":"Excellent","min":27,"max":30,"range":"27–30","desc":"Writing is precise, well-structured, and technically accurate throughout. Abstract and section headings guide the reader effectively. No significant grammatical errors."},{"level":"Good","min":21,"max":26,"range":"21–26","desc":"Writing is mostly clear and well-organised. Minor grammatical issues do not impede understanding. Technical accuracy is high."},{"level":"Developing","min":13,"max":20,"range":"13–20","desc":"Writing conveys the content but lacks precision. Some sections are unclear or poorly structured. Occasional technical inaccuracies."},{"level":"Insufficient","min":0,"max":12,"range":"0–12","desc":"Writing is unclear, poorly structured, or contains significant inaccuracies. Communication of technical content is substantially impaired."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('01b94576-b441-4c66-ac35-be4aa17effa3', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', '3a305bed-e865-444f-a3a3-c92302bd93cf', 'delivery', 'Oral Communication', 'Oral', 30, 30, '#3B82F6', '[{"level":"Excellent","min":27,"max":30,"range":"27–30","desc":"Fluent, structured delivery with effective time management. Team engages the jury with confidence. Q&A demonstrates full project ownership."},{"level":"Good","min":21,"max":26,"range":"21–26","desc":"Delivery is structured and mostly fluent. Most Q&A responses are accurate. Minor hesitation or time management issues."},{"level":"Developing","min":13,"max":20,"range":"13–20","desc":"Delivery is understandable but inconsistent in structure or pace. Some Q&A responses are incomplete or inaccurate."},{"level":"Insufficient","min":0,"max":12,"range":"0–12","desc":"Delivery is poorly structured or largely unclear. The jury cannot follow the presentation. Most Q&A responses are missing or incorrect."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('7a7a05a9-ac9c-402d-aa04-6a07b69dccde', 'e55e0820-93f2-487f-abaa-4ae64a77e93e', 'fda374b5-0bbf-41e3-ad46-29fe1491189b', 'teamwork', 'Team Collaboration', 'Team', 10, 10, '#EF4444', '[{"level":"Excellent","min":9,"max":10,"range":"9–10","desc":"Equal contribution from all members. Clear role delegation and ethical conduct throughout."},{"level":"Good","min":7,"max":8,"range":"7–8","desc":"Most members are engaged. Task distribution is reasonable with minor gaps."},{"level":"Developing","min":4,"max":6,"range":"4–6","desc":"One or two members disproportionately lead. Others contribute minimally."},{"level":"Insufficient","min":0,"max":3,"range":"0–3","desc":"Minimal team cohesion. Roles are unclear or one member dominates entirely."}]', 4) ON CONFLICT DO NOTHING;
