INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('684fe08e-8aeb-4069-a864-a800f0e007aa', 'e14683dc-6ac1-4c73-a2cb-da24e9e4f45f', '93a2a9b8-de26-4fbb-a805-d7134bc8a55f', 'problem_solving', 'Problem Scoping', 'Prob Scope', 25, 25, '#8B5CF6', '[{"level":"Excellent","min":22,"max":25,"range":"22–25","desc":"Problem is rigorously scoped with clear constraints, stakeholder analysis, and measurable success criteria. Literature review is thorough and relevant."},{"level":"Good","min":17,"max":21,"range":"17–21","desc":"Problem scope is well-defined. Constraints and success criteria are identified. Literature review is mostly complete."},{"level":"Developing","min":10,"max":16,"range":"10–16","desc":"Problem is described but scoping is incomplete. Some constraints or success criteria are missing. Limited literature review."},{"level":"Insufficient","min":0,"max":9,"range":"0–9","desc":"Problem is poorly or ambiguously defined. Constraints and success criteria are absent. No meaningful literature review."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('6ddc3532-8a5c-41f0-a01c-80467a94d895', 'e14683dc-6ac1-4c73-a2cb-da24e9e4f45f', '7283938c-881e-46e5-a432-793287f19248', 'system_design', 'Solution Design', 'Sol Design', 25, 25, '#F59E0B', '[{"level":"Excellent","min":22,"max":25,"range":"22–25","desc":"Design is creative, feasible, and fully addresses all requirements. Trade-offs between alternatives are explicitly analysed. Design is well-documented."},{"level":"Good","min":17,"max":21,"range":"17–21","desc":"Design addresses most requirements with clear rationale. Some alternative considered. Documentation mostly complete."},{"level":"Developing","min":10,"max":16,"range":"10–16","desc":"Design is presented but rationale is incomplete. Limited analysis of alternatives. Some requirements not addressed."},{"level":"Insufficient","min":0,"max":9,"range":"0–9","desc":"Design is vague, incomplete, or does not address key requirements. No alternatives considered."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('df2ffbe9-f3d9-4636-aa1a-2208d49f12d6', 'e14683dc-6ac1-4c73-a2cb-da24e9e4f45f', 'c2a960c2-ec12-409c-a49b-14ac9f66a451', 'implementation_quality', 'Implementation', 'Impl', 20, 20, '#22C55E', '[{"level":"Excellent","min":17,"max":20,"range":"17–20","desc":"Implementation is complete and fully functional. Code/hardware is well-organised and meets all specified requirements. Testing is comprehensive."},{"level":"Good","min":13,"max":16,"range":"13–16","desc":"Implementation is mostly complete. Core functionality works. Minor issues in organisation or testing coverage."},{"level":"Developing","min":8,"max":12,"range":"8–12","desc":"Implementation is partially complete. Core functionality is present but some features are missing or buggy."},{"level":"Insufficient","min":0,"max":7,"range":"0–7","desc":"Implementation is largely incomplete or non-functional. Major features missing."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('fb8af623-bf3b-4522-a586-ff6e8bfec072', 'e14683dc-6ac1-4c73-a2cb-da24e9e4f45f', 'cba29dca-3ee3-4e5a-a78a-44034a059a9a', 'communication', 'Communication', 'Comm', 20, 20, '#3B82F6', '[{"level":"Excellent","min":17,"max":20,"range":"17–20","desc":"Communication is clear, professional, and well-structured. All technical and non-technical audiences are served effectively. Documentation is complete."},{"level":"Good","min":13,"max":16,"range":"13–16","desc":"Communication is mostly clear. Minor gaps in clarity or audience adaptation. Documentation mostly complete."},{"level":"Developing","min":8,"max":12,"range":"8–12","desc":"Communication is understandable but inconsistent. Some sections unclear. Documentation incomplete."},{"level":"Insufficient","min":0,"max":7,"range":"0–7","desc":"Communication is poor or unclear. Audience needs are not served. Documentation substantially incomplete."}]', 4) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('d503371e-a85d-4eea-ad83-a91291cf4297', 'e14683dc-6ac1-4c73-a2cb-da24e9e4f45f', 'a0ce2f65-e11f-427c-ab49-6806b15b6ffe', 'teamwork', 'Teamwork & Ethics', 'Team', 10, 10, '#EF4444', '[{"level":"Excellent","min":9,"max":10,"range":"9–10","desc":"All members participate actively and equally. Professional and ethical conduct observed throughout."},{"level":"Good","min":7,"max":8,"range":"7–8","desc":"Most members contribute. Minor knowledge gaps. Professionalism mostly observed."},{"level":"Developing","min":4,"max":6,"range":"4–6","desc":"Uneven participation. Some members are passive or unprepared."},{"level":"Insufficient","min":0,"max":3,"range":"0–3","desc":"Very low participation or dominated by one person. Lack of professionalism observed."}]', 5) ON CONFLICT DO NOTHING;
