INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('b9f1f35c-7929-412b-a2c3-63e14ab7e9d0', 'b90e1112-88c7-44fa-a275-25bc0ad2d96d', '93a2a9b8-de26-4fbb-a805-d7134bc8a55f', 'problem_solving', 'Problem Analysis & Scoping', 'Problem Analysis', 30, 30, '#8B5CF6', '[{"level":"Excellent","min":26,"max":30,"range":"26–30","desc":"Comprehensive problem analysis: stakeholders, constraints, competing requirements, and edge cases are all identified and justified. Demonstrates advanced systems thinking."},{"level":"Good","min":20,"max":25,"range":"20–25","desc":"Thorough problem analysis with clear constraints and stakeholder needs. Some advanced analysis present."},{"level":"Developing","min":12,"max":19,"range":"12–19","desc":"Problem analysis covers the basics but misses key constraints or stakeholder perspectives."},{"level":"Insufficient","min":0,"max":11,"range":"0–11","desc":"Problem is superficially described. Major gaps in analysis, constraints, or stakeholder identification."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('d3dd5fe2-d521-4a2a-ae2b-bb11b6fa0902', 'b90e1112-88c7-44fa-a275-25bc0ad2d96d', '7283938c-881e-46e5-a432-793287f19248', 'system_design', 'Solution Architecture', 'Architecture', 20, 20, '#F59E0B', '[{"level":"Excellent","min":17,"max":20,"range":"17–20","desc":"Architecture is well-structured with clear component interfaces. Design justification is based on trade-off analysis."},{"level":"Good","min":13,"max":16,"range":"13–16","desc":"Architecture is mostly clear. Component roles are defined. Some justification provided."},{"level":"Developing","min":8,"max":12,"range":"8–12","desc":"Architecture is described but interfaces or interactions are unclear. Limited justification."},{"level":"Insufficient","min":0,"max":7,"range":"0–7","desc":"Architecture is poorly defined or missing. Component responsibilities are unclear."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('2a39ada5-da79-4403-aec0-8299b6747419', 'b90e1112-88c7-44fa-a275-25bc0ad2d96d', 'c2a960c2-ec12-409c-a49b-14ac9f66a451', 'implementation_quality', 'Implementation Quality', 'Impl Quality', 25, 25, '#22C55E', '[{"level":"Excellent","min":22,"max":25,"range":"22–25","desc":"High-quality implementation: well-structured, fully functional, and thoroughly tested. Performance meets or exceeds requirements. Code/design is maintainable."},{"level":"Good","min":17,"max":21,"range":"17–21","desc":"Solid implementation. Most functionality complete and tested. Minor quality or performance issues."},{"level":"Developing","min":10,"max":16,"range":"10–16","desc":"Implementation has core functionality but significant gaps in testing or quality. Some features incomplete."},{"level":"Insufficient","min":0,"max":9,"range":"0–9","desc":"Implementation is substantially incomplete. Major functionality missing or non-functional."}]', 3) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('26a1a51f-ab67-405d-a737-b184d060edb8', 'b90e1112-88c7-44fa-a275-25bc0ad2d96d', 'cba29dca-3ee3-4e5a-a78a-44034a059a9a', 'communication', 'Communication Skills', 'Communication', 15, 15, '#3B82F6', '[{"level":"Excellent","min":13,"max":15,"range":"13–15","desc":"Concise, targeted communication. Key messages are delivered clearly in time. Technical accuracy maintained throughout."},{"level":"Good","min":10,"max":12,"range":"10–12","desc":"Communication covers key points clearly. Minor issues with emphasis or time management."},{"level":"Developing","min":6,"max":9,"range":"6–9","desc":"Communication is adequate but lacks focus. Some key points are unclear or missing."},{"level":"Insufficient","min":0,"max":5,"range":"0–5","desc":"Communication is unclear or unfocused. Key information not conveyed effectively."}]', 4) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('5809839f-fbb7-4a4f-a996-72ee4cf60160', 'b90e1112-88c7-44fa-a275-25bc0ad2d96d', 'a0ce2f65-e11f-427c-ab49-6806b15b6ffe', 'teamwork', 'Teamwork & Ethics', 'Team', 10, 10, '#EF4444', '[{"level":"Excellent","min":9,"max":10,"range":"9–10","desc":"Equal contribution from all members. Clear role delegation and ethical conduct throughout."},{"level":"Good","min":7,"max":8,"range":"7–8","desc":"Most members are engaged. Task distribution is reasonable with minor gaps."},{"level":"Developing","min":4,"max":6,"range":"4–6","desc":"One or two members disproportionately lead. Others contribute minimally."},{"level":"Insufficient","min":0,"max":3,"range":"0–3","desc":"Minimal team cohesion. Roles are unclear or one member dominates entirely."}]', 5) ON CONFLICT DO NOTHING;
