INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('f7160a57-742e-4428-ad3a-9ac826e3b2a4', 'bb63166c-d38c-4278-a1e9-5c8b7b081a6c', '9153ef48-d850-40bf-a60b-985c27b85214', 'originality', 'Novelty & Originality', 'Novelty', 30, 30, '#8B5CF6', '[{"level":"Excellent","min":26,"max":30,"range":"26–30","desc":"Clear novel contribution to the field. Hypothesis is creative and not a replication of prior work. The research framing demonstrates independent thinking."},{"level":"Good","min":20,"max":25,"range":"20–25","desc":"Mostly original research framing. Some novel elements with minor overlap with existing work."},{"level":"Developing","min":12,"max":19,"range":"12–19","desc":"Research has partial novelty but significant portions are derivative or replicative."},{"level":"Insufficient","min":0,"max":11,"range":"0–11","desc":"Research is largely a replication or literature review. No significant original contribution identified."}]', 1) ON CONFLICT DO NOTHING;
