INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('bef0ee60-1170-401b-a860-190ae7af1d01', '6c44b363-4522-4cad-a251-06484b72b164', '87559029-8bad-47de-afc6-43faaa45230b', 'creativity', 'Design Creativity', 'Creativity', 30, 30, '#8B5CF6', '[{"level":"Excellent","min":27,"max":30,"range":"27–30","desc":"Design is highly creative: novel approach to the antenna/RF challenge with clear rationale for the non-conventional choices. Innovation is well-motivated."},{"level":"Good","min":21,"max":26,"range":"21–26","desc":"Design shows clear creative thinking. Approach is mostly novel with good rationale."},{"level":"Developing","min":13,"max":20,"range":"13–20","desc":"Some creative elements present but design is largely conventional. Limited exploration of alternatives."},{"level":"Insufficient","min":0,"max":12,"range":"0–12","desc":"Design is conventional with no meaningful creative contribution."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('14b446ba-82d2-4360-a0d5-3d650c766907', '6c44b363-4522-4cad-a251-06484b72b164', 'ee91d9af-bcf4-49a4-a966-cbd063bbb8f5', 'technical_merit', 'Technical Merit', 'Technical', 40, 40, '#F59E0B', '[{"level":"Excellent","min":35,"max":40,"range":"35–40","desc":"Design is technically rigorous: electromagnetic analysis, simulation results, and measured performance are all consistent and meet specifications. Clear understanding of antenna theory demonstrated."},{"level":"Good","min":27,"max":34,"range":"27–34","desc":"Strong technical quality. Analysis and simulation are mostly correct. Measured performance mostly meets specifications."},{"level":"Developing","min":16,"max":26,"range":"16–26","desc":"Technical work is present but has gaps. Some analysis incorrect or simulation results inconsistent with measurements."},{"level":"Insufficient","min":0,"max":15,"range":"0–15","desc":"Technical work has critical errors or is largely absent. Design does not meet specifications."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('c7b88d63-b8b9-4151-ae69-d608d9cc4435', '6c44b363-4522-4cad-a251-06484b72b164', '03cdba6e-ce74-412d-ab8a-8819efca56ba', 'application_and_presentation', 'Application Value', 'Application', 30, 30, '#22C55E', '[{"level":"Excellent","min":27,"max":30,"range":"27–30","desc":"Application is clearly identified and well-motivated. The antenna design is directly suited to the proposed use case. Real-world deployment considerations are addressed."},{"level":"Good","min":21,"max":26,"range":"21–26","desc":"Application is identified with reasonable motivation. Design is mostly suited to the use case. Some deployment considerations addressed."},{"level":"Developing","min":13,"max":20,"range":"13–20","desc":"Application is mentioned but not well-motivated. Design suitability for the use case is only partially demonstrated."},{"level":"Insufficient","min":0,"max":12,"range":"0–12","desc":"No clear application identified, or the design is not suited to the stated application."}]', 3) ON CONFLICT DO NOTHING;
