INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('c33e7c6c-d2a0-4a2a-a56d-61625346ba0d', '47979751-163d-48b3-ae56-a65586d18f1b', '4f8cf9da-b0c7-4a62-ae00-c127f9c6eb8a', 'design_compliance', 'Mission Compliance', 'Compliance', 20, 20, '#6366F1', '[{"level":"Excellent","min":17,"max":20,"range":"17–20","desc":"All design constraints met: mass, volume, and interface specifications fully complied with. Design documentation is complete and accurate."},{"level":"Good","min":13,"max":16,"range":"13–16","desc":"Most design constraints met. Minor deviations documented and justified. Documentation mostly complete."},{"level":"Developing","min":8,"max":12,"range":"8–12","desc":"Some design constraints met. Notable deviations not all justified. Documentation incomplete."},{"level":"Insufficient","min":0,"max":7,"range":"0–7","desc":"Major design constraints not met. Design is non-compliant. Documentation substantially incomplete."}]', 1) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('02116bcb-cbfa-4011-ad98-97f3cf2c7f2d', '47979751-163d-48b3-ae56-a65586d18f1b', '2acdc2ab-1710-48df-a764-c1e4b5e8ec4e', 'mission_execution', 'Mission Performance', 'Performance', 35, 35, '#22C55E', '[{"level":"Excellent","min":31,"max":35,"range":"31–35","desc":"All primary mission objectives are achieved. System performs reliably through all phases of the mission profile. Telemetry data is complete and accurate."},{"level":"Good","min":24,"max":30,"range":"24–30","desc":"Most primary mission objectives achieved. System performs adequately through most mission phases. Telemetry mostly complete."},{"level":"Developing","min":14,"max":23,"range":"14–23","desc":"Some mission objectives achieved. Performance gaps in one or more mission phases. Telemetry partially complete."},{"level":"Insufficient","min":0,"max":13,"range":"0–13","desc":"Most mission objectives not achieved. System fails in critical phases. Telemetry data substantially incomplete."}]', 2) ON CONFLICT DO NOTHING;
INSERT INTO period_criteria (id, period_id, source_criterion_id, key, label, short_label, max_score, weight, color, rubric_bands, sort_order) VALUES ('9ade7fa5-71bd-49c2-ab3b-54b92cad1f11', '47979751-163d-48b3-ae56-a65586d18f1b', '7065e7e2-dffe-49f3-a6bf-2d59c6661b90', 'data_and_documentation', 'Data Quality & Analysis', 'Data', 25, 25, '#F59E0B', '[{"level":"Excellent","min":22,"max":25,"range":"22–25","desc":"Data quality is high: sensors are calibrated, acquisition rate is appropriate, and all required telemetry channels are present. Data analysis is thorough and conclusions well-supported."},{"level":"Good","min":17,"max":21,"range":"17–21","desc":"Good data quality. Most sensors calibrated and data acquisition complete. Analysis is mostly thorough."},{"level":"Developing","min":10,"max":16,"range":"10–16","desc":"Data quality is variable. Some sensors uncalibrated or channels missing. Analysis is partial."},{"level":"Insufficient","min":0,"max":9,"range":"0–9","desc":"Data quality is poor. Significant missing or corrupted channels. Analysis is absent or superficial."}]', 3) ON CONFLICT DO NOTHING;
